class UnifiedResp:
    """Single response schema for all core problems."""
    difficulty_rating: int
    decision: str
    reasoning: str
    answer: str
    confidence: int


# Safety refusal phrases
_SAFETY_REFUSAL_KW = ["i cannot", "i can't", "i apologize", "as an ai",
                      "i'm not able", "i must decline", "i'm unable",
                      "i don't think i should", "it would be inappropriate"]


def _normalize_confidence(raw_conf: int) -> int:
    raw_conf = int(raw_conf)
    if raw_conf > 20:
        return int(max(0, min(20, round(raw_conf / 5))))
    return int(max(0, min(20, raw_conf)))


def _classify_result(response, correct_answer, naive_answer,
                     slop_keywords, problem_type):
    """Classify model response using multi-layer slop detection."""
    ma = str(response.answer).strip().lower()
    cn = str(correct_answer).strip().lower()
    nn = str(naive_answer).strip().lower()
    ic = cn in ma or ma in cn

    # Multi-layer slop detection (Fix 3)
    slop = multi_layer_slop(ma, nn, cn, slop_keywords or [],
                            problem_type)

    # Verbose-correct guard
    if ic:
        slop = False

    conf = _normalize_confidence(response.confidence)
    safety_refusal = any(phrase in ma for phrase in _SAFETY_REFUSAL_KW)
    return {
        "is_correct": ic, "is_naive": nn in ma or ma in nn,
        "semantic_slop": slop,
        "confidence": conf, "model_answer": ma,
        "slop_keywords_found": "",
        "safety_refusal": safety_refusal,
    }


def sanitize_for_protobuf(v):
    """Recursively convert to protobuf-safe types."""
    if v is None: return None
    if isinstance(v, bool): return bool(v)
    if isinstance(v, int): return int(v)
    if isinstance(v, float):
        if math.isnan(v) or math.isinf(v): return 0.0
        return float(v)
    if isinstance(v, str): return str(v)
    if isinstance(v, dict):
        return {str(k): sanitize_for_protobuf(val) for k, val in v.items()}
    if isinstance(v, (list, tuple)):
        return [sanitize_for_protobuf(i) for i in v]
    if hasattr(v, 'item'):
        return sanitize_for_protobuf(v.item())
    return str(v)


def _extract_code(text: str) -> str:
    """Extract Python code ONLY from explicit fenced blocks. (Fix 4B)

    Tightened to prevent reasoning traces from being classified as code.
    Requires: ```python fencing, min 20 chars, at least one code indicator.
    """
    try:
        code = kbench.tools.python.extract_code(text)
        if code and len(code) >= 20:
            # Verify it looks like real code
            indicators = ['=', '(', 'print', 'import', 'def ', 'for ', 'if ']
            if any(ind in code for ind in indicators):
                return code
    except (AttributeError, TypeError):
        pass
    pattern = r'```(?:python|py)\s*\n(.*?)```'
    matches = re.findall(pattern, text, re.DOTALL)
    if not matches:
        return ""
    code = matches[0].strip()
    if len(code) < 20:
        return ""
    indicators = ['=', '(', 'print', 'import', 'def ', 'for ', 'if ']
    if not any(ind in code for ind in indicators):
        return ""
    return code

